export function run(input) {
    const fs = require('fs');
    const findings = [];

    // CLIから渡されるファイルパスを取得 (input.path または input.file)
    const filePath = input.path || input.file;

    if (!filePath) return { findings: [] };

    try {
        const content = fs.readFileSync(filePath, 'utf8');

        if (content.includes('eval(')) {
            const lines = content.split('\n');
            const lineNum = lines.findIndex(line => line.includes('eval(')) + 1;

            findings.push({
                severity: 'CRITICAL',
                file: filePath,
                line: lineNum,
                message: 'Dangerous eval() detected.'
            });
        }
    } catch (err) {
        // バイナリファイルなどで読み込めない場合はスキップ
    }

    return { findings };
}
